const input = $input.first().json;

if (!input.jobId) throw new Error('jobId ausente');
if (!input.projectId) throw new Error('projectId ausente');
if (!input.callbacks?.successUrl || !input.callbacks?.failureUrl || !input.callbacks?.token) {
  throw new Error('callbacks incompletos');
}
if (!input.productContext?.productName) throw new Error('productContext.productName ausente');

return [{
  json: {
    ...input,
    sourceImages: Array.isArray(input.sourceImages) ? input.sourceImages : [],
    targetMarketplaces: Array.isArray(input.productContext?.targetMarketplaces)
      ? input.productContext.targetMarketplaces.join(', ')
      : '',
  }
}];

const data = $input.first().json;
const ctx = data.productContext;
const imageLines = (data.sourceImages || []).map((img, index) => `Imagem ${index + 1}: ${img.fileUrl}`).join('
');

const userPrompt = `Voce e um especialista em criacao de anuncios para Shopee e Mercado Livre.

Sua tarefa e gerar 3 titulos e 1 descricao de produto com foco em conversao e busca organica.

Dados do produto:
- Nome: ${ctx.productName}
- Categoria: ${ctx.category || ''}
- Contexto: ${ctx.shortContext || ''}
- Cor: ${ctx.color || ''}
- Material: ${ctx.material || ''}
- Dimensoes: ${ctx.dimensionsXcm || ''} cm x ${ctx.dimensionsYcm || ''} cm x ${ctx.dimensionsZcm || ''} cm
- Peso: ${ctx.weightGrams || ''} g
- Voltagem: ${ctx.voltage || ''}
- Marketplaces alvo: ${data.targetMarketplaces}
- Idioma: ${data.language || 'pt-BR'}

Imagens de referencia:
${imageLines || 'Nenhuma imagem informada'}

Gere:
- 3 titulos, cada um com uma estrategia diferente: SEO, informativa e criativa
- 1 descricao curta, completa, natural e persuasiva
- 3 bullets
- 3 palavras-chave SEO

Regras:
- nao invente atributos nao sustentados pelas imagens ou contexto
- nao use emoji
- nao seja prolixo
- retorne somente JSON valido

Formato:
{
  "titles": [
    "titulo seo",
    "titulo informativo",
    "titulo criativo"
  ],
  "description": "descricao do produto",
  "bullets": [
    "bullet 1",
    "bullet 2",
    "bullet 3"
  ],
  "seoKeywords": [
    "keyword 1",
    "keyword 2",
    "keyword 3"
  ]
}`;

return [{
  json: {
    ...data,
    openAiBody: {
      model: $env.OPENAI_TEXT_MODEL || 'gpt-4.1-mini',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'Voce gera anuncios para marketplaces brasileiros. Responda apenas JSON valido.'
        },
        {
          role: 'user',
          content: userPrompt
        }
      ]
    }
  }
}];

const previous = $items('Build OpenAI Prompt', 0, 0)[0].json;
const response = $input.first().json;

function failurePayload(message) {
  return [{
    json: {
      callbackUrl: previous.callbacks.failureUrl,
      callbackToken: previous.callbacks.token,
      callbackPayload: {
        jobId: previous.jobId,
        jobType: 'text_generation',
        provider: 'openai',
        errorCode: 'TEXT_GENERATION_FAILED',
        errorMessage: message,
      }
    }
  }];
}

if (response.error) {
  return failurePayload(typeof response.error === 'string' ? response.error : JSON.stringify(response.error));
}

const content = response.choices?.[0]?.message?.content;
if (!content) {
  return failurePayload('Resposta vazia do provider de texto');
}

let parsed;
try {
  parsed = JSON.parse(content);
} catch (error) {
  return failurePayload(`Falha ao interpretar JSON do modelo: ${error.message}`);
}

if (!Array.isArray(parsed.titles) || !parsed.description) {
  return failurePayload('JSON retornado pelo modelo nao contem titles/description validos');
}

return [{
  json: {
    callbackUrl: previous.callbacks.successUrl,
    callbackToken: previous.callbacks.token,
    callbackPayload: {
      jobId: previous.jobId,
      jobType: 'text_generation',
      provider: 'openai',
      result: {
        titles: parsed.titles,
        description: parsed.description,
        bullets: Array.isArray(parsed.bullets) ? parsed.bullets : [],
        seoKeywords: Array.isArray(parsed.seoKeywords) ? parsed.seoKeywords : [],
      }
    }
  }
}];
